import { execute, query } from "../database";

interface SettingRow {
  key: string;
  value: string;
}

export async function getSetting(key: string): Promise<string | null> {
  const rows = await query<SettingRow>("SELECT key, value FROM settings WHERE key = $1", [key]);
  return rows[0]?.value ?? null;
}

export async function setSetting(key: string, value: string): Promise<void> {
  await execute(
    `INSERT INTO settings (key, value) VALUES ($1, $2)
     ON CONFLICT (key) DO UPDATE SET value = excluded.value`,
    [key, value],
  );
}

export async function resetAllSettings(): Promise<void> {
  await execute("DELETE FROM settings", []);
}

export async function getAllSettings(): Promise<Record<string, string>> {
  const rows = await query<SettingRow>("SELECT key, value FROM settings", []);
  return Object.fromEntries(rows.map((r) => [r.key, r.value]));
}

// ---- Calendar helpers (plan M23) ----------------------------------------

export const CALENDAR_SETTING_KEY = "game_calendar";

export interface CalendarJSON {
  year: number;
  dayOfYear: number;
}

/** Reads the stored calendar for a chat, or returns null if never set. */
export async function getCalendarSetting(chatId: string): Promise<CalendarJSON | null> {
  const key = `${CALENDAR_SETTING_KEY}_${chatId}`;
  const raw = await getSetting(key);
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw) as CalendarJSON;
    if (typeof parsed.year === "number" && typeof parsed.dayOfYear === "number") {
      return parsed;
    }
  } catch {
    // fall through
  }
  return null;
}

/** Persists the calendar JSON for a chat. */
export async function setCalendarSetting(chatId: string, cal: CalendarJSON): Promise<void> {
  const key = `${CALENDAR_SETTING_KEY}_${chatId}`;
  await setSetting(key, JSON.stringify(cal));
}

import Database from "@tauri-apps/plugin-sql";

const DB_URL = "sqlite:mysillytavern.db";
const CACHE_TTL = 5_000; // 5 seconds

let dbPromise: Promise<Database> | null = null;

/** Lazily opens (and caches) the single SQLite connection for the app. */
export function getDb(): Promise<Database> {
  if (!dbPromise) {
    dbPromise = Database.load(DB_URL);
  }
  return dbPromise;
}

// -- Query cache --
const cache = new Map<string, { data: unknown; expires: number }>();

function cacheKey(sql: string, params: unknown[]): string {
  return `${sql}|${JSON.stringify(params)}`;
}

/** Clear the entire cache. Called after any write (execute). */
export function invalidateCache(): void {
  cache.clear();
}

export async function query<T>(sql: string, params: unknown[] = []): Promise<T[]> {
  const key = cacheKey(sql, params);
  const entry = cache.get(key);
  if (entry && entry.expires > Date.now()) {
    return entry.data as T[];
  }
  const db = await getDb();
  const result = await db.select<T[]>(sql, params);
  cache.set(key, { data: result, expires: Date.now() + CACHE_TTL });
  return result;
}

export async function execute(sql: string, params: unknown[] = []): Promise<void> {
  const db = await getDb();
  await db.execute(sql, params);
  // Any write invalidates the entire cache — simple and safe
  cache.clear();
}

export function newId(): string {
  return crypto.randomUUID();
}

export function nowIso(): string {
  return new Date().toISOString();
}

import { useState } from "react";
import { useTranslation } from "react-i18next";

import { resetAllSettings } from "../../db/repositories/settingsRepo";
import { AppearancePanel } from "./AppearancePanel";
import { BackupPanel } from "./BackupPanel";
import { ConnectionsPanel } from "./ConnectionsPanel";
import { DiagnosticsPanel } from "./DiagnosticsPanel";
import { MemorySettingsPanel } from "./MemorySettingsPanel";
import { PresetsPanel } from "./PresetsPanel";
import { TtsPanel } from "./TtsPanel";
import { UsagePanel } from "./UsagePanel";

export function SettingsScreen() {
  const { t } = useTranslation("settings");
  const [resetDone, setResetDone] = useState(false);

  return (
    <div className="mx-auto flex max-w-3xl flex-col gap-6 px-6 py-8">
      <h1 className="font-[var(--font-display)] text-2xl">{t("title")}</h1>
      <ConnectionsPanel />
      <PresetsPanel />
      <MemorySettingsPanel />
      <AppearancePanel />
      <TtsPanel />
      <BackupPanel />
      <UsagePanel />
      <DiagnosticsPanel />
      <div className="border-t pt-4" style={{ borderColor: "var(--color-border)" }}>
        <button
          type="button"
          onClick={async () => {
            if (confirm(t("resetConfirm") ?? "Obnovit výchozí nastavení?")) {
              await resetAllSettings();
              setResetDone(true);
              setTimeout(() => setResetDone(false), 2000);
              window.location.reload();
