import { execute, newId, nowIso, query } from "../database";

export interface Summary {
  id: string;
  chatId: string;
  upToMessageId: string;
  text: string;
  createdAt: string;
  updatedAt: string;
}

interface SummaryRow {
  id: string;
  chat_id: string;
  up_to_message_id: string;
  text: string;
  created_at: string;
  updated_at: string;
}

function toSummary(row: SummaryRow): Summary {
  return {
    id: row.id,
    chatId: row.chat_id,
    upToMessageId: row.up_to_message_id,
    text: row.text,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

/** One row per chat (`summaries.chat_id` is UNIQUE) — null when nothing has
 * been summarized yet. */
export async function getSummary(chatId: string): Promise<Summary | null> {
  const rows = await query<SummaryRow>("SELECT * FROM summaries WHERE chat_id = $1", [chatId]);
  return rows[0] ? toSummary(rows[0]) : null;
}

/** Inserts the chat's summary row if it doesn't exist yet, otherwise
 * overwrites its text and advances `up_to_message_id` — the single
 * write-path both the summarizer and manual panel edits use. */
export async function upsertSummary(
  chatId: string,
  upToMessageId: string,
  text: string,
): Promise<Summary> {
  const existing = await getSummary(chatId);
  const now = nowIso();
  if (existing) {
    await execute(
      `UPDATE summaries SET up_to_message_id = $2, text = $3, updated_at = $4 WHERE chat_id = $1`,
      [chatId, upToMessageId, text, now],
    );
    return { ...existing, upToMessageId, text, updatedAt: now };
  }
  const id = newId();
  await execute(
    `INSERT INTO summaries (id, chat_id, up_to_message_id, text, created_at, updated_at)
     VALUES ($1, $2, $3, $4, $5, $5)`,
    [id, chatId, upToMessageId, text, now],
  );
  return { id, chatId, upToMessageId, text, createdAt: now, updatedAt: now };
}

/** Manual edit from the memory panel — rewrites the text only, keeps
 * `up_to_message_id` where it is. */
export async function updateSummaryText(chatId: string, text: string): Promise<void> {
  await execute("UPDATE summaries SET text = $2, updated_at = $3 WHERE chat_id = $1", [
    chatId,
    text,
    nowIso(),
  ]);
}

import { execute, newId, nowIso, query } from "../database";

export type QuestStatus = "active" | "completed" | "failed";

export interface Quest {
  id: string;
  chatId: string;
  name: string;
  description: string;
  status: QuestStatus;
  createdAt: string;
  updatedAt: string;
}

interface QuestRow {
  id: string;
  chat_id: string;
  name: string;
  description: string;
  status: string;
  created_at: string;
  updated_at: string;
}

function toQuest(row: QuestRow): Quest {
  return {
    id: row.id,
    chatId: row.chat_id,
    name: row.name,
    description: row.description,
    status: row.status as QuestStatus,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

/** List all quests for a chat, active first, then completed, then failed. */
export async function listQuests(chatId: string): Promise<Quest[]> {
  const rows = await query<QuestRow>(
    `SELECT * FROM quests WHERE chat_id = $1
     ORDER BY CASE status
       WHEN 'active' THEN 0
       WHEN 'completed' THEN 1
       WHEN 'failed' THEN 2
     END, created_at ASC`,
    [chatId],
  );
  return rows.map(toQuest);
}

/** Get a single quest by name within a chat (for upsert logic). */
export async function getQuestByName(
  chatId: string,
  name: string,
): Promise<Quest | null> {
  const rows = await query<QuestRow>(
    "SELECT * FROM quests WHERE chat_id = $1 AND name = $2",
    [chatId, name],
  );
  return rows[0] ? toQuest(rows[0]) : null;
}

export interface CreateQuestInput {
  chatId: string;
  name: string;
  description?: string;
}

/** Create a new quest (active by default). */
export async function createQuest(input: CreateQuestInput): Promise<Quest> {
  const id = newId();
  const now = nowIso();
  await execute(
    `INSERT INTO quests (id, chat_id, name, description, status, created_at, updated_at)
     VALUES ($1, $2, $3, $4, 'active', $5, $5)`,
    [id, input.chatId, input.name, input.description ?? "", now],
  );
  return {
    id,
    chatId: input.chatId,
    name: input.name,
    description: input.description ?? "",
    status: "active",
    createdAt: now,
    updatedAt: now,
  };
}

/** Update a quest's status (active / completed / failed). */
export async function updateQuestStatus(
  id: string,
  status: QuestStatus,
): Promise<void> {
  await execute(
    "UPDATE quests SET status = $2, updated_at = $3 WHERE id = $1",
    [id, status, nowIso()],
  );
}

/** Append a progress note to the quest description. */
export async function addQuestNote(id: string, note: string): Promise<void> {
  const now = nowIso();
  await execute(
    `UPDATE quests SET
       description = CASE
         WHEN description = '' THEN $2
         ELSE description || '\n' || $2
       END,
       updated_at = $3
     WHERE id = $1`,
    [id, note, now],
  );
}

import { useEffect } from "react";
import { HashRouter, Navigate, Route, Routes } from "react-router-dom";

import { getAutoBackupEnabled, getAutoBackupMaxCount, runAutoBackup } from "./db/backup";
import { useSettingsStore } from "./stores/settingsStore";
import { CardEditor } from "./ui/characters/CardEditor";
import { GalleryScreen } from "./ui/characters/GalleryScreen";
import { ChatListScreen } from "./ui/chat/ChatListScreen";
import { ChatScreen } from "./ui/chat/ChatScreen";
import { AppShell } from "./ui/layout/AppShell";
import { LorebookEditor } from "./ui/lorebooks/LorebookEditor";
import { LorebooksListScreen } from "./ui/lorebooks/LorebooksListScreen";
import { PersonasScreen } from "./ui/personas/PersonasScreen";
import { SettingsScreen } from "./ui/settings/SettingsScreen";

function App() {
  const { hydrated, hydrate } = useSettingsStore();

  useEffect(() => {
    void hydrate();
  }, [hydrate]);

  // Startup auto-backup (M14.1) — driven from the frontend so it can respect
  // the settings stored in SQLite and checkpoint the WAL before zipping.
  useEffect(() => {
    void (async () => {
      try {
        if (await getAutoBackupEnabled()) {
          await runAutoBackup(await getAutoBackupMaxCount());
        }
      } catch (err) {
        console.warn("startup auto-backup failed:", err);
      }
    })();
  }, []);

  if (!hydrated) {
    return null;
  }

  return (
    <HashRouter>
      <AppShell>
        <Routes>
          <Route path="/" element={<ChatListScreen />} />
          <Route path="/chat/:id" element={<ChatScreen />} />
          <Route path="/characters" element={<GalleryScreen />} />
          <Route path="/characters/:id" element={<CardEditor />} />
          <Route path="/personas" element={<PersonasScreen />} />
          <Route path="/lorebooks" element={<LorebooksListScreen />} />
          <Route path="/lorebooks/:id" element={<LorebookEditor />} />
          <Route path="/settings" element={<SettingsScreen />} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </AppShell>
    </HashRouter>
  );
}

export default App;

