+          e.image_path ?? e.imagePath ?? null,
+          e.updated_at ?? e.updatedAt ?? entry.ts,
+        ],
+      );
+    }
+    // else: local is newer — keep local. No conflict tracking for Phase 3.
+  } else {
+    // Insert new fact
+    await execute(
